import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = edge_distance.copy()

    # Parameters for damping the effects of highly used edges
    damping_factor = 0.01
    damping_threshold = 5

    # Adjust distances inversely based on usage, applying a damping if usage exceeds a threshold
    for i in range(updated_edge_distance.shape[0]):
        for j in range(updated_edge_distance.shape[1]):
            if edge_n_used[i, j] > damping_threshold:
                updated_edge_distance[i, j] *= (1 + damping_factor * np.log(edge_n_used[i, j] - damping_threshold + 1))

    # Apply additional increase based on local_opt_tours
    increase_factor = 0.05
    for tour in local_opt_tours:
        for i in range(len(tour) - 1):
            updated_edge_distance[tour[i], tour[i+1]] += increase_factor
            updated_edge_distance[tour[i+1], tour[i]] += increase_factor
        # Also increment the edge closing the tour cycle
        if tour[-1] != tour[0]:
            updated_edge_distance[tour[-1], tour[0]] += increase_factor
            updated_edge_distance[tour[0], tour[-1]] += increase_factor

    return updated_edge_distance

import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = edge_distance.copy()
    max_usage = np.max(edge_n_used)

    # Define penalty and reward as a function of edge usage
    def penalty(edge_usage):
        return 1.0 + 0.1 * (edge_usage / max_usage)

    def reward(edge_usage):
        return 1.0 - 0.1 * (edge_usage / max_usage)

    n = edge_distance.shape[0]

    # Adjusting edge weights based on the tours and edge usage
    for tour in local_opt_tours:
        for i in range(len(tour) - 1):
            edge_from = tour[i]
            edge_to = tour[i + 1]
            # Apply penalty to edges used in local optimum tours based on edge usage
            updated_edge_distance[edge_from, edge_to] *= penalty(edge_n_used[edge_from, edge_to])
            updated_edge_distance[edge_to, edge_from] *= penalty(edge_n_used[edge_to, edge_from])

    # Apply rewards to all edges not part of the local optimal routes
    for i in range(n):
        for j in range(n):
            # Reward less used edges with a reward factor calculated from its usage
            if not any(((i, j) in zip(tour[:-1], tour[1:])) or ((j, i) in zip(tour[:-1], tour[1:])) for tour in local_opt_tours):
                updated_edge_distance[i, j] *= reward(edge_n_used[i, j])
                updated_edge_distance[j, i] *= reward(edge_n_used[j, i])

    return updated_edge_distance

import numpy as np

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Variable inflation factors depending on frequency usage
    base_inflation_factor = 1.05
    high_usage_inflation = 1.15

    # Update the count of how many times each edge has been used
    n = edge_distance.shape[0]
    for tour in local_opt_tours:
        for i in range(len(tour)):
            if i == len(tour) - 1:
                from_node, to_node = tour[i], tour[0]
            else:
                from_node, to_node = tour[i], tour[i+1]
            edge_n_used[from_node, to_node] += 1
            edge_n_used[to_node, from_node] += 1

    # Determine the high usage and very high usage thresholds
    high_usage_threshold = np.percentile(edge_n_used, 70)
    very_high_usage_threshold = np.percentile(edge_n_used, 90)

    # Update distances based on the defined thresholds
    updated_edge_distance = np.copy(edge_distance)
    for i in range(n):
        for j in range(n):
            if edge_n_used[i, j] >= very_high_usage_threshold:
                updated_edge_distance[i, j] *= high_usage_inflation
            elif edge_n_used[i, j] >= high_usage_threshold:
                updated_edge_distance[i, j] *= base_inflation_factor

    return updated_edge_distance
